import argparse
import base64
import json
import mimetypes
import os
from pathlib import Path
import sys
import requests


def read_api_key():
    return os.environ.get("GEMINI_API_KEY") or os.environ.get("GOOGLE_API_KEY")


def file_to_part(path: Path):
    mime = mimetypes.guess_type(str(path))[0] or "application/octet-stream"
    data = base64.b64encode(path.read_bytes()).decode("ascii")
    return {"inline_data": {"mime_type": mime, "data": data}}


def extract_image(resp_json):
    candidates = resp_json.get("candidates") or []
    for cand in candidates:
        content = cand.get("content") or {}
        parts = content.get("parts") or []
        for part in parts:
            inline = part.get("inlineData") or part.get("inline_data")
            if not inline:
                continue
            mime = inline.get("mimeType") or inline.get("mime_type") or "application/octet-stream"
            data = inline.get("data")
            if data and mime.startswith("image/"):
                return mime, base64.b64decode(data)
    return None, None


def extract_text(resp_json):
    out = []
    for cand in resp_json.get("candidates") or []:
        content = cand.get("content") or {}
        for part in content.get("parts") or []:
            text = part.get("text")
            if text:
                out.append(text)
    return "\n".join(out).strip()


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("--prompt", required=True)
    ap.add_argument("--out", required=True)
    ap.add_argument("--input")
    ap.add_argument("--model", default="gemini-2.5-flash-image")
    args = ap.parse_args()

    api_key = read_api_key()
    if not api_key:
        print("Missing GEMINI_API_KEY or GOOGLE_API_KEY", file=sys.stderr)
        sys.exit(2)

    out_path = Path(args.out).expanduser().resolve()
    out_path.parent.mkdir(parents=True, exist_ok=True)

    parts = [{"text": args.prompt}]
    if args.input:
        in_path = Path(args.input).expanduser().resolve()
        if not in_path.exists():
            print(f"Input image not found: {in_path}", file=sys.stderr)
            sys.exit(2)
        parts.append(file_to_part(in_path))

    payload = {
        "contents": [{"role": "user", "parts": parts}],
        "generationConfig": {"responseModalities": ["TEXT", "IMAGE"]},
    }

    url = f"https://generativelanguage.googleapis.com/v1beta/models/{args.model}:generateContent?key={api_key}"
    r = requests.post(url, headers={"Content-Type": "application/json"}, data=json.dumps(payload), timeout=180)

    if not r.ok:
        print(r.text, file=sys.stderr)
        sys.exit(1)

    data = r.json()
    mime, img_bytes = extract_image(data)
    if img_bytes:
        out_path.write_bytes(img_bytes)
        print(str(out_path))
        return

    text = extract_text(data)
    if text:
        print(text, file=sys.stderr)
    else:
        print(json.dumps(data, indent=2), file=sys.stderr)
    sys.exit(1)


if __name__ == "__main__":
    main()

